function nextGeneration(aliveCells: number[][]): number[][] {
  const alive = new Set(aliveCells.map(([x, y]) => `${x},${y}`));
  const neighborCounts = new Map<string, number>();

  for (const [x, y] of aliveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = `${x + dx},${y + dy}`;
        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
      }
    }
  }

  const result: number[][] = [];
  for (const [key, count] of neighborCounts) {
    if (alive.has(key) && (count === 2 || count === 3)) {
      result.push(key.split(",").map(Number));
    } else if (!alive.has(key) && count === 3) {
      result.push(key.split(",").map(Number));
    }
  }

  return result;
}

export function advanceGame(aliveCells: number[][], steps: number): number[][] {
  if (steps === 0) return aliveCells;
  return nextGeneration(aliveCells);
}

